def _save_fuel_market_scan(data):
    SystemSetting.set(_FUEL_MARKET_SCAN_KEY, json.dumps(data or {}, ensure_ascii=True))


def _scan_fuel_market_rates(force=False):
    """Scan PSO for today's rate. Stores per-date rates in a 'rates' dict."""
    today_s = pk_date().strftime('%Y-%m-%d')
    current = _read_fuel_market_scan()
    rates = current.get('rates') or {}
    if not force and today_s in rates and rates[today_s].get('ok'):
        current['scan_date'] = today_s
        return current

    try:
        pso = _scan_pso_rates()
    except Exception as exc:
        pso = {
            'source': 'PSO',
            'ok': False,
            'petrol': None,
            'diesel': None,
            'updated_at': '',
            'error': str(exc)[:220],
        }

    scanned_at = pk_now().strftime('%d-%m-%Y %I:%M:%S %p')
    rates[today_s] = {
        'ok': pso.get('ok', False),
        'petrol': pso.get('petrol'),
        'diesel': pso.get('diesel'),
        'scanned_at': scanned_at,
        'error': pso.get('error', ''),
    }

    scan_payload = {
        'scan_date': today_s,
        'scanned_at': scanned_at,
        'status': 'ok' if pso.get('ok') else 'error',
        'sources': {'pso': pso},
        'rates': rates,
    }
    _save_fuel_market_scan(scan_payload)
    return scan_payload


@app.route('/api/fuel-market-rates')
def api_fuel_market_rates():
    data = _scan_fuel_market_rates(force=False)
    return jsonify(data or {})


@app.route('/api/fuel-market-rate-for-date')
def api_fuel_market_rate_for_date():
    """Return PSO rate for a specific date.

    Scan policy:
    - Today: live scan allowed (if DB record missing).
    - Non-today dates: DB-only (no live scan).
    """
    date_input = (request.args.get('date') or '').strip()
    parsed_date = parse_date(date_input)
    date_str = parsed_date.strftime('%Y-%m-%d') if parsed_date else date_input
    scan_data = _read_fuel_market_scan()
    rates = scan_data.get('rates') or {}

    today_s = pk_date().strftime('%Y-%m-%d')
    if date_str == today_s:
        scan_data = _scan_fuel_market_rates(force=False)
        rates = scan_data.get('rates') or {}

    if date_str in rates and rates[date_str].get('ok'):
        entry = rates[date_str]
        return jsonify({
            'ok': True,
            'petrol': entry.get('petrol'),
            'diesel': entry.get('diesel'),
            'scan_date': date_str,
            'scanned_at': entry.get('scanned_at', ''),
        })

    return jsonify({
        'ok': False,
        'petrol': None,
        'diesel': None,
        'scan_date': date_str,
        'scanned_at': '',
        'no_record_date': date_input or date_str,
    })



