@app.route('/api/vehicle-family-options/add', methods=['POST'])
def vehicle_family_option_add_api():
    name = (request.get_json(silent=True) or {}).get('name', '')
    name = (name or '').strip()
    if not name:
        return jsonify({'ok': False, 'message': 'Name is required'}), 400
