@app.errorhandler(CSRFError)
def handle_csrf_error(e):
    """Redirect back to the originating page with a helpful flash instead of bare 400."""
    flash('Session expired or form was re-submitted. Please try again.', 'warning')
    referrer = request.referrer or url_for('dashboard')
    return redirect(referrer)


@app.route('/r2-proxy')
def r2_proxy():
    """Serve an R2 object through Flask so JS canvas can draw it without CORS taint."""
    from urllib.parse import urlparse
    import urllib.request
    import urllib.error
    from r2_storage import R2_PUBLIC_URL as _r2_pub

    url = request.args.get('url', '').strip()
    if not url:
        return make_response('Missing url', 400)

    p = urlparse(url)
    if p.scheme not in ('http', 'https') or not p.netloc:
        return make_response('Invalid url', 400)

    allow_hosts = set()
    if _r2_pub:
        try:
            allow_hosts.add(urlparse(_r2_pub).netloc.lower())
        except Exception:
            pass
    host = (p.netloc or '').lower()
    if not (host.endswith('.r2.dev') or host.endswith('.r2.cloudflarestorage.com') or host in allow_hosts):
        return make_response(f'Host not allowed: {host}', 400)

    try:
        req = urllib.request.Request(url, headers={
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
            'Accept': 'image/avif,image/webp,image/apng,image/*,*/*;q=0.8',
        })
        with urllib.request.urlopen(req, timeout=25) as r:
            data = r.read()
            ct = r.headers.get('Content-Type') or 'application/octet-stream'

        if not data:
            return make_response('Upstream returned empty response', 502)
        if ct.lower().startswith('text/html'):
            return make_response('Upstream returned HTML, not an image. File may be missing on R2.', 502)

        resp = make_response(data)
        resp.headers['Content-Type'] = ct
        resp.headers['Cache-Control'] = 'private, max-age=3600'
        resp.headers['Access-Control-Allow-Origin'] = '*'
        return resp
    except urllib.error.HTTPError as e:
        code = e.code or 502
        body = ''
        try:
            body = e.read(500).decode('utf-8', errors='ignore')
        except Exception:
            pass
        return make_response(f'Upstream {code}: {body[:200]}', code)
    except Exception as e:
        return make_response(f'Proxy failed: {str(e)}', 502)


@app.route('/driver/<int:driver_id>/delete-document', methods=['POST'])
def driver_delete_document(driver_id):
    """AJAX: delete a single saved document/photo field from DB + R2."""
    ALLOWED_FIELDS = {
        'photo_path', 'cnic_front_path', 'cnic_back_path',
        'license_front_path', 'license_back_path', 'document_path'
    }
    data = request.get_json(force=True) or {}
    field = data.get('field', '').strip()
    if field not in ALLOWED_FIELDS:
        return jsonify({'ok': False, 'error': 'Invalid field'}), 400
    driver = Driver.query.get_or_404(driver_id)
    current_val = getattr(driver, field, None)
    if current_val:
        try:
            from r2_storage import delete_file_by_url as _r2_del
            _r2_del(current_val)
        except Exception:
            pass
        setattr(driver, field, None)
        db.session.commit()
    return jsonify({'ok': True})


@app.route('/driver/add', methods=['GET', 'POST'])
@app.route('/driver/edit/<int:id>', methods=['GET', 'POST'])
def driver_form(id=None):
    # Post dropdown: sirf Full Name (short name nahi)
    posts = EmployeePost.query.order_by(EmployeePost.full_name).all()
    post_choices = [('', '-- Select Post --')] + [
        (p.full_name, p.full_name) for p in posts
    ]

    if id:
        driver = Driver.query.get_or_404(id)
        form = DriverForm(obj=driver)
        # Edit: agar driver ki post import se aayi hai aur master mein nahi hai, to choices mein add karo taake change na ho
        if driver.post and driver.post.strip():
            existing_values = [c[0] for c in post_choices]
            if driver.post.strip() not in existing_values:
                post_choices = post_choices + [(driver.post.strip(), driver.post.strip())]
        form.post.choices = post_choices
        if driver.application_date:
            if isinstance(driver.application_date, str):
                form.application_date.data = parse_date(driver.application_date)
            else:
                form.application_date.data = driver.application_date
        title = f"Edit Driver - {driver.name}"
    else:
        driver = Driver()
        form = DriverForm()
        form.post.choices = post_choices
        title = "Add New Driver"
    if form.validate_on_submit():
        try:
            u = None
            form.populate_obj(driver)
            # Always recalculate status server-side — do not rely on JS hidden fields
            _today = pk_date()
            driver.cnic_status = ('Valid' if driver.cnic_expiry_date >= _today else 'Expired') if driver.cnic_expiry_date else None
            driver.license_status = ('Valid' if driver.license_expiry_date >= _today else 'Expired') if driver.license_expiry_date else None
            if not id:
                db.session.add(driver)
            db.session.commit()
            try:
                from routes_finance import _auto_create_coa_account
                _auto_create_coa_account('driver', driver.id, driver.name, extra_label=driver.driver_id)
                db.session.commit()
            except Exception:
                pass
            from r2_storage import upload_image_file as _r2_img, upload_pdf_file as _r2_pdf, R2_PUBLIC_URL as _r2_url
            from r2_storage import R2_ACCESS_KEY_ID as _r2_key, R2_ENDPOINT_URL as _r2_ep, R2_BUCKET_NAME as _r2_bkt
            _use_r2 = bool(_r2_url and _r2_key and _r2_ep and _r2_bkt)
            _any_upload = False

            _r2_warnings = []

            def _save_image(file_storage, field_attr, r2_folder, local_fname):
                nonlocal _any_upload
                if not (file_storage and file_storage.filename):
                    return
                file_storage.seek(0)
                if _use_r2:
                    try:
                        url = _r2_img(file_storage, folder=r2_folder)
                        if url:
                            setattr(driver, field_attr, url)
                            _any_upload = True
                            return
                    except Exception as e:
                        app.logger.error('R2 upload failed for %s: %s', field_attr, e)
                        _r2_warnings.append(field_attr)
                        return
                else:
                    _r2_warnings.append(field_attr)
                    return

            def _save_pdf(file_storage, field_attr, r2_folder, local_fname):
                nonlocal _any_upload
                if not (file_storage and file_storage.filename):
                    return
                file_storage.seek(0)
                if _use_r2:
                    try:
                        url = _r2_pdf(file_storage, folder=r2_folder)
                        if url:
                            setattr(driver, field_attr, url)
                            _any_upload = True
                            return
                    except Exception as e:
                        app.logger.error('R2 PDF upload failed for %s: %s', field_attr, e)
                        _r2_warnings.append(field_attr)
                        return
                else:
                    _r2_warnings.append(field_attr)
                    return

            _save_image(request.files.get('photo'),         'photo_path',         'drivers/photos',   'photo')
            _save_image(request.files.get('cnic_front'),    'cnic_front_path',    'drivers/cnic',     'cnic_front')
            _save_image(request.files.get('cnic_back'),     'cnic_back_path',     'drivers/cnic',     'cnic_back')
            _save_image(request.files.get('license_front'), 'license_front_path', 'drivers/license',  'license_front')
            _save_image(request.files.get('license_back'),  'license_back_path',  'drivers/license',  'license_back')
            _save_pdf(request.files.get('document'),        'document_path',      'drivers/documents','document')

            if _any_upload:
                db.session.commit()
            if _r2_warnings:
                flash(f"Warning: {len(_r2_warnings)} file(s) could not be uploaded — Cloudflare R2 is not configured. Files skipped: {', '.join(_r2_warnings)}. Please set R2 environment variables.", 'warning')
            if not id and driver.cnic_no and (driver.cnic_no or '').strip() and driver.vehicle_id:
                post_id, role_id = None, None
                if driver.post and (driver.post or '').strip():
                    emp_post = EmployeePost.query.filter(EmployeePost.full_name == (driver.post or '').strip()).first()
                    if emp_post:
                        post_id = emp_post.id
                        role_id = emp_post.role_id
                u = _create_user_for_employee_or_driver(driver.cnic_no.strip(), driver.name, post_id, role_id)
                if u:
                    flash("Driver saved! Login user bhi ban gaya: User ID = CNIC, pehli dafa password 123 se login karein, phir naya password set karein.", 'success')
            if id or not (not id and driver.cnic_no and (driver.cnic_no or '').strip() and u):
                flash(f"Driver '{driver.name}' successfully {'updated' if id else 'added'}!", 'success')
            return redirect(url_for('drivers_list'))
        except IntegrityError:
            db.session.rollback()
            flash('Duplicate entry: Driver ID, CNIC, or License No already exists in the system.', 'danger')
        except Exception as e:
            db.session.rollback()
            flash(f"Error saving driver: {str(e)}", 'danger')
    relation_suggestions = [
        r[0] for r in db.session.query(Driver.emergency_relation)
        .filter(Driver.emergency_relation != None, Driver.emergency_relation != '')
        .distinct().order_by(Driver.emergency_relation).all()
    ]
    return render_template('driver_form.html', form=form, title=title, driver=driver,
                           relation_suggestions=relation_suggestions)
# Employees (non-driver staff)
# ────────────────────────────────────────────────
@app.route('/employees')
def employees_list():
    from auth_utils import get_user_context
    
    user_id = session.get('user_id')
    user_context = get_user_context(user_id) if user_id else {}
    allowed_projects = user_context.get('allowed_projects', set())
    allowed_districts = user_context.get('allowed_districts', set())
    is_master_or_admin = user_context.get('is_master_or_admin', False)
    
    search = request.args.get('search', '').strip()
    from_date_str = request.args.get('from_date', '').strip()
    to_date_str = request.args.get('to_date', '').strip()
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 20, type=int)
    sort_by = request.args.get('sort_by', 'name')
    sort_order = request.args.get('sort_order', 'asc')

    def _dmy(s):
        from datetime import datetime as _dt
        try: return _dt.strptime(s, '%d-%m-%Y').date() if s else None
        except ValueError: return None

    from_date = _dmy(from_date_str)
    to_date = _dmy(to_date_str)

    query = Employee.query

    # Apply user data scope - employees assigned to user's projects/districts
    if not is_master_or_admin:
        if allowed_projects or allowed_districts:
            from sqlalchemy import or_
            filters = []
            if allowed_projects:
                filters.append(Employee.projects.any(Project.id.in_(list(allowed_projects))))
            if allowed_districts:
                filters.append(Employee.districts.any(District.id.in_(list(allowed_districts))))
            if filters:
                query = query.filter(or_(*filters))

    if search:
        flt = _multi_word_filter(search,
            Employee.name, Employee.code, Employee.department,
            Employee.cnic_no, Employee.phone1, Employee.father_name)
        if flt is not None:
            query = query.filter(flt)
    if from_date:
        query = query.filter(Employee.joining_date >= from_date)
    if to_date:
        query = query.filter(Employee.joining_date <= to_date)

    # Apply sorting based on sort_by column
    if sort_by == 'code':
        order_col = Employee.code.asc() if sort_order == 'asc' else Employee.code.desc()
    elif sort_by == 'cnic':
        order_col = Employee.cnic_no.asc() if sort_order == 'asc' else Employee.cnic_no.desc()
    elif sort_by == 'post':
        order_col = Employee.post_id.asc() if sort_order == 'asc' else Employee.post_id.desc()
    elif sort_by == 'department':
        order_col = Employee.department.asc() if sort_order == 'asc' else Employee.department.desc()
    elif sort_by == 'phone':
        order_col = Employee.phone.asc() if sort_order == 'asc' else Employee.phone.desc()
    else:  # default to name
        order_col = Employee.name.asc() if sort_order == 'asc' else Employee.name.desc()

    pagination = query.order_by(order_col).paginate(page=page, per_page=per_page, error_out=False)
    employees = pagination.items
    return render_template('employees_list.html', employees=employees, search=search,
                           from_date=from_date_str, to_date=to_date_str,
                           pagination=pagination, per_page=per_page, sort_by=sort_by, sort_order=sort_order)


@app.route('/employee/add', methods=['GET', 'POST'])
@app.route('/employee/edit/<int:id>', methods=['GET', 'POST'])
def employee_form(id=None):
    # Build Employee Post dropdown (id-based, shows full + short name)
    posts = EmployeePost.query.order_by(EmployeePost.full_name).all()
    post_choices = [(0, '-- Select Post --')] + [
        (p.id, f"{p.full_name} ({p.short_name})") for p in posts
    ]

    # Department history (distinct existing departments)
    dept_rows = (
        db.session.query(Employee.department)
        .filter(Employee.department.isnot(None), Employee.department != '')
        .distinct()
        .order_by(Employee.department)
        .all()
    )
    departments = [row[0] for row in dept_rows]

    # Tab: 1=Basic, 2=Contact, 3=Documents (optional)
    tab = request.args.get('tab', 1, type=int)
    if tab < 1 or tab > 3:
        tab = 1
    if not id and tab > 1:
        return redirect(url_for('employee_form', tab=1))

    emp = Employee.query.get(id) if id else None
    if id and not emp:
        abort(404)
    title = f"Edit Employee - {emp.name}" if emp else "Add New Employee"

    form1 = EmployeeFormStep1()
    form1.post_id.choices = post_choices
    form2 = EmployeeFormStep2()

    if emp:
        form1.code.data = emp.code
        form1.name.data = emp.name
        form1.post_id.data = emp.post_id or 0
        form1.department.data = emp.department or ''
        form1.father_name.data = emp.father_name or ''
        form1.place_of_birth.data = emp.place_of_birth or ''
        form1.dob.data = parse_date(emp.dob) if isinstance(emp.dob, str) else emp.dob
        form1.education.data = emp.education or ''
        form1.marital_status.data = emp.marital_status or ''
        form1.cnic_no.data = emp.cnic_no or ''
        form1.district.data = emp.district or ''
        form1.address.data = emp.address or ''
        form1.joining_date.data = parse_date(emp.joining_date) if isinstance(emp.joining_date, str) else emp.joining_date
        form2.phone1.data = emp.phone1 or ''
        form2.phone2.data = emp.phone2 or ''
        form2.email.data = emp.email or ''
        form2.status.data = emp.status or 'Active'
        form2.bank_name.data = emp.bank_name or ''
        form2.account_no.data = emp.account_no or ''
        form2.account_title.data = emp.account_title or ''
        form2.remarks.data = emp.remarks or ''

    doc_form = EmployeeDocumentForm()
    employee_documents = list(emp.documents) if emp else []

    if request.method == 'POST':
        action = request.form.get('action')

        if action == 'save_step_1':
            form1 = EmployeeFormStep1(request.form)
            form1.post_id.choices = post_choices
            if form1.validate():
                try:
                    code_val = (form1.code.data or '').strip()
                    if not code_val:
                        year = pk_now().year
                        last_emp = Employee.query.order_by(Employee.id.desc()).first()
                        next_num = (last_emp.id + 1) if last_emp else 1
                        code_val = f"EMP-{year}-{next_num:04d}"
                    if not emp:
                        emp = Employee(code=code_val)
                        db.session.add(emp)
                    emp.code = code_val
                    emp.name = (form1.name.data or '').strip()
                    emp.post_id = form1.post_id.data if form1.post_id.data else None
                    emp.department = (form1.department.data or '').strip()
                    emp.father_name = (form1.father_name.data or '').strip()
                    emp.place_of_birth = (form1.place_of_birth.data or '').strip()
                    emp.dob = form1.dob.data
                    emp.education = (form1.education.data or '').strip()
                    emp.marital_status = (form1.marital_status.data or '').strip()
                    emp.cnic_no = (form1.cnic_no.data or '').strip()
                    emp.district = (form1.district.data or '').strip()
                    emp.address = (form1.address.data or '').strip()
                    emp.joining_date = form1.joining_date.data
                    db.session.commit()
                    try:
                        from routes_finance import _auto_create_coa_account
                        _auto_create_coa_account('employee', emp.id, emp.name, extra_label=emp.code)
                        db.session.commit()
                    except Exception:
                        pass
                    flash('Step 1 saved. Ab Contact & Job bharo.', 'success')
                    return redirect(url_for('employee_form', id=emp.id, tab=2))
                except Exception as e:
                    db.session.rollback()
                    flash(f'Error: {str(e)}', 'danger')
            tab = 1

        elif action == 'save_step_2' and emp:
            form2 = EmployeeFormStep2(request.form)
            if form2.validate():
                try:
                    emp.phone1 = (form2.phone1.data or '').strip()
                    emp.phone2 = (form2.phone2.data or '').strip()
                    emp.email = (form2.email.data or '').strip()
                    # joining_date pehle hi Step 1 me required aur save ho chuki hoti hai
                    emp.status = (form2.status.data or 'Active').strip()
                    emp.bank_name = (form2.bank_name.data or '').strip()
                    emp.account_no = (form2.account_no.data or '').strip()
                    emp.account_title = (form2.account_title.data or '').strip()
                    emp.remarks = (form2.remarks.data or '').strip()
                    db.session.commit()
                    if emp.cnic_no and (emp.status or '').strip() == 'Active':
                        _sync_user_active_by_cnic(emp.cnic_no.strip(), True)
                    flash('Step 2 saved. Documents tab par jayein (optional) ya Done dabayein.', 'success')
                    return redirect(url_for('employee_form', id=emp.id, tab=3))
                except Exception as e:
                    db.session.rollback()
                    flash(f'Error: {str(e)}', 'danger')
            tab = 2

        elif action == 'add_document' and emp:
            doc_form = EmployeeDocumentForm()
            doc_file = request.files.get('document')
            if doc_file and doc_file.filename:
                try:
                    from werkzeug.utils import secure_filename
                    ext = os.path.splitext(doc_file.filename)[1].lower() or '.bin'
                    allowed = {'.pdf', '.jpg', '.jpeg', '.png', '.gif', '.webp', '.doc', '.docx'}
                    if ext not in allowed:
                        flash('Sirf PDF, image, ya Word file upload karein.', 'danger')
                    else:
                        subdir = os.path.join(app.config['UPLOAD_FOLDER'], 'employees', str(emp.id))
                        os.makedirs(subdir, exist_ok=True)
                        fname = secure_filename(doc_file.filename)
                        if not fname:
                            fname = 'doc' + ext
                        file_path = os.path.join(subdir, fname)
                        doc_file.save(file_path)
                        rel_path = os.path.join('employees', str(emp.id), fname).replace('\\', '/')
                        doc_title = (request.form.get('title') or '').strip() or fname
                        doc = EmployeeDocument(employee_id=emp.id, title=doc_title or None, file_path=rel_path)
                        db.session.add(doc)
                        db.session.commit()
                        flash('Document save ho gaya.', 'success')
                    return redirect(url_for('employee_form', id=emp.id, tab=3))
                except Exception as e:
                    db.session.rollback()
                    flash(f'Error: {str(e)}', 'danger')
            else:
                flash('Pehle file select karein.', 'warning')
                return redirect(url_for('employee_form', id=emp.id, tab=3))
            tab = 3

    step1_done = emp is not None
    step2_done = emp is not None
    employee_documents = list(emp.documents) if emp else []
    return render_template(
        'employee_form.html',
        form1=form1, form2=form2, doc_form=doc_form,
        title=title, employee=emp, departments=departments,
        tab=tab, step1_done=step1_done, step2_done=step2_done,
        employee_documents=employee_documents,
    )


